You can use the `HttpClient` class in ASP.NET Core to proxy requests to another endpoint. Here's a simple example:

```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet]
    public async Task<IActionResult> Get(string url)
    {
        var httpClient = _httpClientFactory.CreateClient();
        var response = await httpClient.GetAsync(url);
        response.EnsureSuccessStatusCode();
        return new OkObjectResult(await response.Content.ReadAsStringAsync());
    }

    [HttpPost]
    public async Task<IActionResult> Post(string url, [FromBody] string data)
    {
        var httpClient = _httpClientFactory.CreateClient();
        var content = new StringContent(data, Encoding.UTF8, "text/plain");
        var response = await httpClient.PostAsync(url, content);
        response.EnsureSuccessStatusCode();
        return new OkObjectResult(await response.Content.ReadAsStringAsync());
    }
}
```

