import { createContext, useContext, useState, useEffect } from 'react';
import { NotificationProps } from '../helpers/notification.helpers';

interface NotificationContextType {
  notificationElem: HTMLHuelNotificationElement | null;
  notify: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextType>({
  notificationElem: null,
  notify: () => Promise.resolve(),
});

const useNotification = (): NotificationContextType => {
  const [notificationElem, setNotificationElem] = useState<HTMLHuelNotificationElement | null>(null);
  const [notify, setNotify] = useState<NotificationProps>(() => () => Promise.resolve());

  useEffect(() => {
    const element = document.querySelector('huel-notification');
    if (element) {
      setNotificationElem(element);
      setNotify((props) => async () => {
        const { heading, subheading, type } = props;
        await element.open({ heading, subheading, type });
      });
    }
  }, []);

  return { notificationElem, notify };
};

export default useNotification;
export { NotificationContext };
```

